 1	import { PaginationProps, ToolbarItemProps } from '@patternfly/react-core';
 2	import { UsePaginationEffectsArgs, usePaginationEffects } from './usePaginationEffects';
 3	
 4	/**
 5	 * Args for usePaginationPropHelpers that come from outside useTablePropHelpers
 6	 * - Partially satisfied by the object returned by useTableState (TableState)
 7	 * - Makes up part of the arguments object taken by useTablePropHelpers (UseTablePropHelpersArgs)
 8	 *
 9	 * @see TableState
10	 * @see UseTablePropHelpersArgs
11	 */
12	export type UsePaginationPropHelpersExternalArgs = UsePaginationEffectsArgs & {
13	  /**
14	   * The total number of items in the entire un-filtered, un-paginated table (the size of the entire API collection
15	   * being tabulated).
16	   */
17	  totalItemCount: number;
18	};
19	
20	/**
21	 * Returns derived state and prop helpers for the pagination feature based on given "source of truth" state.
22	 * - Used internally by useTablePropHelpers
23	 * - "Derived state" here refers to values and convenience functions derived at render time.
24	 * - "source of truth" (persisted) state and "derived state" are kept separate to prevent out-of-sync duplicated state.
25	 */
26	export const usePaginationPropHelpers = (args: UsePaginationPropHelpersExternalArgs) => {
27	  const {
28	    totalItemCount,
29	    pagination: { pageNumber, itemsPerPage, setPageNumber, setItemsPerPage }
30	  } = args;
31	
32	  usePaginationEffects(args);
33	
34	  /**
35	   * Props for the PF Pagination component
36	   */
37	  const paginationProps: PaginationProps = {
38	    itemCount: totalItemCount,
39	    perPage: itemsPerPage,
40	    page: pageNumber,
41	    onSetPage: (_event, pageNumber) => setPageNumber?.(pageNumber),
42	    onPerPageSelect: (_event, perPage) => {
43	      setPageNumber?.(1);
44	      setItemsPerPage?.(perPage);
45	    }
46	  };
47	
48	  /**
49	   * Props for the PF ToolbarItem component which contains the Pagination component
50	   */
51	  const paginationToolbarItemProps: ToolbarItemProps = {
52	    variant: 'pagination',
53	    align: { default: 'alignRight' }
54	  };
55	
56	  return { paginationProps, paginationToolbarItemProps };
57	};

